description:
Add compile-time validation of Jinja templates in #[render(...)] attributes. Catch errors at compile time, not runtime.

Location: crates/baml-bridge-derive/src/lib.rs (or a separate validation module)

Add minijinja as a dependency for template parsing:
```toml
[dependencies]
minijinja = { version = "...", default-features = false }  # syntax parsing only
```

Validation checks:
```rust
fn validate_template(
    source: &str,
    struct_fields: &[syn::Field],
    allow_dynamic: bool,
) -> Result<(), syn::Error> {
    // 1. Parse template syntax
    let ast = minijinja::parse_template(source)
        .map_err(|e| syn::Error::new(Span::call_site(), format\!(
            "Jinja syntax error: {}", e
        )))?;

    // 2. Collect referenced identifiers (value.foo, value.bar)
    let refs = collect_field_refs(&ast);

    // 3. Validate against struct fields (unless allow_dynamic)
    if \!allow_dynamic {
        for ref_name in refs {
            if \!struct_fields.iter().any(|f| f.ident.as_ref().map(|i| i.to_string()) == Some(ref_name.clone())) {
                return Err(syn::Error::new(Span::call_site(), format\!(
                    "Template references unknown field 'value.{}'. Use #[render(allow_dynamic = true)] for dynamic access.",
                    ref_name
                )));
            }
        }
    }

    // 4. Validate filter names against known set
    let known_filters = ["truncate", "slice_chars", "format_count", "length", "sum", "regex_match"];
    for filter in collect_filter_refs(&ast) {
        if \!known_filters.contains(&filter.as_str()) {
            return Err(syn::Error::new(Span::call_site(), format\!(
                "Template uses unknown filter '{}'", filter
            )));
        }
    }

    Ok(())
}
```
